const b = $json.body || $json;
const clean = (v) => (v ?? '').toString().trim();
const caseId = Number(clean(b.case_id));
const docType = clean(b.doc_type) || 'comunicacion_cliente';
const instructions = clean(b.instructions);
const valid = Number.isFinite(caseId) && caseId > 0;
return [{json:{ valid, error: valid ? '' : 'case_id es requerido', case_id: caseId, doc_type: docType, instructions }}];

