SELECT c.id, c.summary, c.matter_type, c.status, c.priority, c.assigned_lawyer, cl.full_name
FROM cases c
JOIN clients cl ON cl.id = c.client_id
WHERE c.id = {{ $json.case_id }}
LIMIT 1;

SELECT event_type, event_payload, created_at
FROM case_events
WHERE case_id = {{ $('Validar Solicitud').item.json.case_id }}
ORDER BY created_at DESC
LIMIT 5;

