const caseRows = $('Buscar Caso').all();
if (caseRows.length === 0) {
  return [{ json: { found: false } }];
}
const c = caseRows[0].json;
const events = $input.all().map(x => x.json);
const req = $('Validar Solicitud').item.json;
const lines = [];
lines.push('BORRADOR PARA REVISION');
lines.push(`Tipo: ${req.doc_type}`);
lines.push(`Caso #${c.id} - Cliente: ${c.full_name}`);
lines.push('');
lines.push('Objetivo del documento:');
lines.push(`- ${req.instructions || 'Comunicar estado y proximos pasos del caso.'}`);
lines.push('');
lines.push('Contexto resumido:');
lines.push(`- Asunto: ${c.matter_type}`);
lines.push(`- Estado: ${c.status}`);
lines.push(`- Prioridad: ${c.priority}`);
lines.push(`- Resumen: ${c.summary || 'Sin resumen'}`);
lines.push('');
lines.push('Borrador:');
lines.push('Estimado/a cliente,');
lines.push('Con base en la informacion disponible, compartimos el estado actual del caso y acciones recomendadas.');
lines.push('Este texto requiere revision del abogado responsable antes de su envio final.');
lines.push('');
lines.push('Puntos a validar por abogado:');
lines.push('- Exactitud de hechos y fechas');
lines.push('- Riesgos juridicos y estrategia');
lines.push('- Adecuacion a normativa aplicable');
return [{json:{ found:true, case_id:c.id, doc_type:req.doc_type, draft_text: lines.join('\n'), events_used: events.length }}];
